const runId = $input.first().json.runId;
const blueprint = $input.first().json.blueprint || {};
const brdModel = $input.first().json.brdModel || {};
const gapAnalysis = $input.first().json.gapAnalysis || {};

const canonicalSections = blueprint.canonicalSections || [
  'Executive Summary',
  'Background & Business Context',
  'Business Need & Problem Statement',
  'Objectives & Success Criteria',
  'Scope',
  'Stakeholder Register',
  'Functional Requirements',
  'Non-Functional Requirements',
  'Process Flows & Use Cases',
  'Integration Requirements',
  'Reporting & Data Requirements',
  'Assumptions & Constraints',
  'Risks & Mitigation',
  'Dependencies',
  'Acceptance Criteria',
  'Appendices & Open Questions'
];

console.log(`[WF07][${runId}] Generating ${canonicalSections.length} sections...`);

// Return one item per section for parallel/sequential processing
return canonicalSections.map((sectionName, index) => ({
  json: {
    runId,
    sectionIndex: index,
    sectionName,
    totalSections: canonicalSections.length,
    brdModel,
    blueprint,
    gapAnalysis,
    source: $input.first().json.source,
    options: $input.first().json.options,
    isWeakSection: (gapAnalysis.weakSections || []).includes(sectionName),
    isMissingSection: (gapAnalysis.missingSections || []).includes(sectionName)
  }
}));

const item = $input.first().json;
const { runId, sectionName, brdModel, blueprint, gapAnalysis, source, isWeakSection, isMissingSection } = item;

// Extract relevant source chunks for this section
const relevantSections = (source.sections || []).filter(s => 
  s.title?.toLowerCase().includes(sectionName.toLowerCase().split(' ')[0]) ||
  sectionName.toLowerCase().includes((s.title||'').toLowerCase().split(' ')[0])
);
const relevantText = relevantSections.map(s => s.content).join('\n\n').substring(0, 2000) 
  || source.plainText?.substring(0, 1500) || '';

const styleRules = blueprint.styleRules || {};
const gapNote = isWeakSection 
  ? `NOTE: This section was identified as WEAK in the gap analysis — expand with more detail.`
  : isMissingSection 
  ? `NOTE: This section was MISSING from the source — construct it from available context, clearly marking assumptions.`
  : '';

const prompt = `You are a senior consulting business analyst writing a BRD section.

Section to write: ${sectionName}
${gapNote}

Style rules:
- Tone: ${styleRules.tone || 'formal_consulting'}
- Verbosity: ${styleRules.verbosity || 'medium'}
- Use tables: ${styleRules.tableUsage ? 'yes where appropriate' : 'no'}
- Use bullets: ${styleRules.bulletsPreferred ? 'yes' : 'sparingly'}

Relevant source content for this section:
${relevantText || '[No direct source content for this section - use BRD model data below]'}

Full BRD Model (use as source of facts):
Project: ${brdModel.projectName || 'Unknown'}
Business Problem: ${brdModel.businessProblem || ''}
Objectives: ${JSON.stringify(brdModel.objectives || [])}
Stakeholders: ${JSON.stringify((brdModel.stakeholders || []).slice(0, 5))}
FRs (first 5): ${JSON.stringify((brdModel.functionalRequirements || []).slice(0, 5))}
NFRs (first 5): ${JSON.stringify((brdModel.nonFunctionalRequirements || []).slice(0, 5))}
Risks: ${JSON.stringify((brdModel.risks || []).slice(0, 5))}
Assumptions: ${JSON.stringify((brdModel.assumptions || []).slice(0, 5))}

Gap analysis recommendations relevant to this section:
${(gapAnalysis.recommendations || []).filter(r => r.toLowerCase().includes(sectionName.toLowerCase().split(' ')[0])).join('\n') || 'None specific'}

Write the "${sectionName}" section now.
Rules:
- Only use facts from the source. Mark inferred content as [Assumed] or [To Be Confirmed].
- Write in professional consulting prose.
- Return ONLY valid JSON in this format:
{
  "sectionName": "${sectionName}",
  "content": "full markdown content of the section",
  "assumptionsUsed": ["list of assumptions made"],
  "openQuestions": ["any open questions for this section"],
  "confidence": 0.0
}`;

return [{ json: { ...item, sectionPrompt: prompt } }];

const item = $('Prepare Section Prompt').first().json;
const rawResponse = $input.first().json.text || $input.first().json.content || '';

let sectionResult;
try {
  const clean = rawResponse.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  sectionResult = JSON.parse(clean);
} catch(e) {
  console.warn(`[WF07][${item.runId}][${item.sectionName}] Parse failed, using raw text`);
  sectionResult = {
    sectionName: item.sectionName,
    content: rawResponse,
    assumptionsUsed: [],
    openQuestions: [],
    confidence: 0.5
  };
}

return [{
  json: {
    runId: item.runId,
    sectionIndex: item.sectionIndex,
    sectionName: sectionResult.sectionName || item.sectionName,
    content: sectionResult.content || '',
    assumptionsUsed: sectionResult.assumptionsUsed || [],
    openQuestions: sectionResult.openQuestions || [],
    confidence: sectionResult.confidence || 0.8
  }
}];

// Pass through to WF08 with the run context
const firstItem = $input.first().json;
return [{
  json: {
    runId: firstItem.runId,
    sectionsGenerated: $input.all().length,
    message: `All ${$input.all().length} sections generated`
  }
}];
